// --- helpers ---

func firstParticipant(s string) string {
	if s == "" {
		return ""
	}
	parts := splitComma(s)
	if len(parts) == 0 {
		return s
	}
	return parts[0]
}

func splitComma(s string) []string {
	if s == "" {
		return nil
	}
	var out []string
	start := 0
	for i, c := range s {
		if c == ',' {
			out = append(out, s[start:i])
			start = i + 1
		}
	}
	out = append(out, s[start:])
	return out
}

func nonSystemTags(tags []emailqueries.TagReadModel) []emailqueries.TagReadModel {
	var out []emailqueries.TagReadModel
	for _, t := range tags {
		if !t.System {
			out = append(out, t)
		}
	}
	return out
}

func formatRelTime(t time.Time) string {
	if t.IsZero() {
		return ""
	}
	now := time.Now()
	diff := now.Sub(t)
	switch {
	case diff < time.Minute:
		return "now"
	case diff < time.Hour:
		return fmt.Sprintf("%dm ago", int(diff.Minutes()))
	case diff < 24*time.Hour:
		return fmt.Sprintf("%dh ago", int(diff.Hours()))
	default:
		return t.Format("Jan 2")
	}
}

func formatSize(bytes int64) string {
	switch {
	case bytes < 1024:
		return fmt.Sprintf("%dB", bytes)
	case bytes < 1024*1024:
		return fmt.Sprintf("%dKB", bytes/1024)
	default:
		return fmt.Sprintf("%dMB", bytes/(1024*1024))
	}
}

func pageEnd(r emailqueries.ThreadListResult) int {
	end := (r.Page + 1) * r.PageSize
	if end > r.Total {
		end = r.Total
	}
	return end
}

